/**
 * $
 *
 * @param {string} name           - ページ名
 * @param {string} [category='']  - カテゴリ名
 * @returns {object}
 */
const $ = (name, category = '') => {
  const [, _link] = name.match(/^portfolio_works_(.+)_00$/);
  const link = _link.replace(/_/g, '-');

  return {
    name,
    category,
    link
  };
};

